// // This module calculates the 2's complement of a 4-bit binary input by inverting the bits and subtracting 1
module twos_complement(
    input [3:0] binary_input,
    output reg [3:0] twos_complement_output
);

always @(*) begin
    twos_complement_output = ~binary_input + 1;
end

endmodule
